import{_ as i,c as a,o as e,aj as n}from"./chunks/framework.CynFBi0q.js";const c=JSON.parse('{"title":"《AI Agent 应用开发实战》目录大纲","description":"","frontmatter":{},"headers":[],"relativePath":"handbook/ai-agent/index.md","filePath":"handbook/ai-agent/index.md","lastUpdated":1781319967000}'),t={name:"handbook/ai-agent/index.md"};function r(h,l,d,g,o,A){return e(),a("div",null,[...l[0]||(l[0]=[n('<h1 id="《ai-agent-应用开发实战》目录大纲" tabindex="-1">《AI Agent 应用开发实战》目录大纲 <a class="header-anchor" href="#《ai-agent-应用开发实战》目录大纲" aria-label="Permalink to “《AI Agent 应用开发实战》目录大纲”">​</a></h1><p>这份目录结构专为实战型技术书籍设计，涵盖了从基础理论、核心技术栈、架构设计到多领域场景落地的全流程。全书共 16 章，二级标题根据内容深度严格扩展至 5 个，旨在帮助读者构建完整的 AI Agent 知识体系。</p><h2 id="第-1-章-ai-agent-概览-开启智能体时代" tabindex="-1">第 1 章 AI Agent 概览：开启智能体时代 <a class="header-anchor" href="#第-1-章-ai-agent-概览-开启智能体时代" aria-label="Permalink to “第 1 章 AI Agent 概览：开启智能体时代”">​</a></h2><ul><li>1.1 从 Chatbot 到 Agent：人工智能的进化之路</li><li>1.2 AI Agent 的核心定义与基本架构（感知-规划-行动）</li><li>1.3 主流 Agent 开发框架对比（LangChain, AutoGPT, MetaGPT 等）</li><li>1.4 本书学习路线与实战环境搭建指南</li><li>1.5 Agent 伦理边界与社会责任初探</li></ul><h2 id="第-2-章-核心技术栈-大语言模型与-prompt-工程" tabindex="-1">第 2 章 核心技术栈：大语言模型与 Prompt 工程 <a class="header-anchor" href="#第-2-章-核心技术栈-大语言模型与-prompt-工程" aria-label="Permalink to “第 2 章 核心技术栈：大语言模型与 Prompt 工程”">​</a></h2><ul><li>2.1 大语言模型（LLM）的工作原理与能力边界</li><li>2.2 Prompt Engineering 进阶：思维链与少样本提示</li><li>2.3 结构化输出：让模型精准返回 JSON 与代码</li><li>2.4 模型微调与蒸馏：打造垂直领域的专属大脑</li><li>2.5 提示词安全：防御注入攻击与越狱尝试</li></ul><h2 id="第-3-章-记忆系统-构建-agent-的长期与短期记忆" tabindex="-1">第 3 章 记忆系统：构建 Agent 的长期与短期记忆 <a class="header-anchor" href="#第-3-章-记忆系统-构建-agent-的长期与短期记忆" aria-label="Permalink to “第 3 章 记忆系统：构建 Agent 的长期与短期记忆”">​</a></h2><ul><li>3.1 上下文窗口管理：短期记忆的维持与优化</li><li>3.2 向量数据库基础：Embedding 与相似度检索</li><li>3.3 长期记忆实现：基于 Redis 与向量库的混合存储</li><li>3.4 记忆压缩与总结：如何处理无限对话历史</li><li>3.5 记忆遗忘机制：模拟人类记忆的衰减与更新</li></ul><h2 id="第-4-章-规划与推理-赋予-agent-思考的能力" tabindex="-1">第 4 章 规划与推理：赋予 Agent 思考的能力 <a class="header-anchor" href="#第-4-章-规划与推理-赋予-agent-思考的能力" aria-label="Permalink to “第 4 章 规划与推理：赋予 Agent 思考的能力”">​</a></h2><ul><li>4.1 任务分解：ReAct 框架与思维树（ToT）解析</li><li>4.2 反思机制：Self-Reflection 与代码解释器的应用</li><li>4.3 多步推理：复杂逻辑下的决策路径优化</li><li>4.4 幻觉抑制：基于事实核查的推理增强</li><li>4.5 动态规划调整：应对环境反馈的实时策略修正</li></ul><h2 id="第-5-章-工具使用-连接外部世界的桥梁" tabindex="-1">第 5 章 工具使用：连接外部世界的桥梁 <a class="header-anchor" href="#第-5-章-工具使用-连接外部世界的桥梁" aria-label="Permalink to “第 5 章 工具使用：连接外部世界的桥梁”">​</a></h2><ul><li>5.1 工具定义的标准化：OpenAPI 与 Function Calling</li><li>5.2 搜索引擎集成：实时信息获取与 RAG 基础</li><li>5.3 代码执行器：沙箱环境下的 Python 代码运行</li><li>5.4 自定义 API 封装：让 Agent 调用企业内部服务</li><li>5.5 工具选择策略：多工具场景下的路由与优先级</li></ul><h2 id="第-6-章-多智能体协作-从单兵作战到群体智能" tabindex="-1">第 6 章 多智能体协作：从单兵作战到群体智能 <a class="header-anchor" href="#第-6-章-多智能体协作-从单兵作战到群体智能" aria-label="Permalink to “第 6 章 多智能体协作：从单兵作战到群体智能”">​</a></h2><ul><li>6.1 多智能体系统架构：中心化与去中心化模式</li><li>6.2 角色扮演与协作：基于 LangGraph 的状态机设计</li><li>6.3 辩论与共识：多 Agent 解决复杂问题的机制</li><li>6.4 案例解析：软件公司模拟与自动化新闻编辑部</li><li>6.5 协作冲突解决：资源竞争与任务分配的仲裁机制</li></ul><h2 id="第-7-章-检索增强生成-打造知识库驱动型-agent" tabindex="-1">第 7 章 检索增强生成：打造知识库驱动型 Agent <a class="header-anchor" href="#第-7-章-检索增强生成-打造知识库驱动型-agent" aria-label="Permalink to “第 7 章 检索增强生成：打造知识库驱动型 Agent”">​</a></h2><ul><li>7.1 RAG 全流程解析：数据清洗、分块与索引</li><li>7.2 高级检索策略：混合搜索与重排序技术</li><li>7.3 知识图谱与 Agent 的结合：结构化数据的利用</li><li>7.4 解决 RAG 痛点：丢失中间内容与多跳推理</li><li>7.5 知识库动态更新：增量索引与版本管理策略</li></ul><h2 id="第-8-章-agent-前端交互与可视化" tabindex="-1">第 8 章 Agent 前端交互与可视化 <a class="header-anchor" href="#第-8-章-agent-前端交互与可视化" aria-label="Permalink to “第 8 章 Agent 前端交互与可视化”">​</a></h2><ul><li>8.1 构建 Agent 对话界面：Streamlit 与 Gradio 实战</li><li>8.2 流式输出：提升用户体验的关键技术</li><li>8.3 可视化调试：追踪 Agent 的思考链与工具调用</li><li>8.4 多模态交互：语音与图像输入的集成</li><li>8.5 用户反馈闭环：点赞、纠错与 RLHF 数据收集</li></ul><h2 id="第-9-章-实战项目一-智能数据分析-agent" tabindex="-1">第 9 章 实战项目一：智能数据分析 Agent <a class="header-anchor" href="#第-9-章-实战项目一-智能数据分析-agent" aria-label="Permalink to “第 9 章 实战项目一：智能数据分析 Agent”">​</a></h2><ul><li>9.1 需求分析：从自然语言到 SQL 与图表</li><li>9.2 数据预处理与 Schema 映射策略</li><li>9.3 代码生成与执行：PandasAI 的核心实现</li><li>9.4 安全围栏：防止恶意代码执行与数据泄露</li><li>9.5 结果解释：将数据洞察转化为自然语言报告</li></ul><h2 id="第-10-章-实战项目二-自动化研发运维-agent" tabindex="-1">第 10 章 实战项目二：自动化研发运维 Agent <a class="header-anchor" href="#第-10-章-实战项目二-自动化研发运维-agent" aria-label="Permalink to “第 10 章 实战项目二：自动化研发运维 Agent”">​</a></h2><ul><li>10.1 场景定义：自动化代码审查与 Bug 修复</li><li>10.2 上下文构建：解析代码仓库与依赖关系</li><li>10.3 交互式调试：Agent 如何读取日志与重启服务</li><li>10.4 集成 CI/CD 流水线：GitHub Actions 与 Agent 的结合</li><li>10.5 运维知识沉淀：故障复盘与知识库自动更新</li></ul><h2 id="第-11-章-实战项目三-个性化教育辅导-agent" tabindex="-1">第 11 章 实战项目三：个性化教育辅导 Agent <a class="header-anchor" href="#第-11-章-实战项目三-个性化教育辅导-agent" aria-label="Permalink to “第 11 章 实战项目三：个性化教育辅导 Agent”">​</a></h2><ul><li>11.1 教学设计：苏格拉底式提问法的 Prompt 实现</li><li>11.2 知识追踪：根据学生表现动态调整难度</li><li>11.3 多模态教学：生成数学公式与几何图形</li><li>11.4 情感计算：识别学生情绪并给予鼓励</li><li>11.5 学习效果评估：基于测试数据的自适应反馈</li></ul><h2 id="第-12-章-实战项目四-电商销售与服务-agent" tabindex="-1">第 12 章 实战项目四：电商销售与服务 Agent <a class="header-anchor" href="#第-12-章-实战项目四-电商销售与服务-agent" aria-label="Permalink to “第 12 章 实战项目四：电商销售与服务 Agent”">​</a></h2><ul><li>12.1 智能导购：基于用户画像的商品推荐</li><li>12.2 售后处理：自动退换货流程与工单系统对接</li><li>12.3 主动营销：基于时间触发的客户关怀</li><li>12.4 转化率优化：A/B 测试在 Agent 话术中的应用</li><li>12.5 客户情绪安抚：投诉场景下的共情与升级策略</li></ul><h2 id="第-13-章-评估与评测-如何衡量-agent-的好坏" tabindex="-1">第 13 章 评估与评测：如何衡量 Agent 的好坏 <a class="header-anchor" href="#第-13-章-评估与评测-如何衡量-agent-的好坏" aria-label="Permalink to “第 13 章 评估与评测：如何衡量 Agent 的好坏”">​</a></h2><ul><li>13.1 评估指标体系：准确性、鲁棒性与效率</li><li>13.2 自动化评测框架：Ragas 与 TruLens 实战</li><li>13.3 基于 LLM 的评估：用 GPT-5 给 Agent 打分</li><li>13.4 构建黄金测试集：回归测试与持续集成</li><li>13.5 人工评估流程：众包标注与专家审核规范</li></ul><h2 id="第-14-章-性能优化与成本控制" tabindex="-1">第 14 章 性能优化与成本控制 <a class="header-anchor" href="#第-14-章-性能优化与成本控制" aria-label="Permalink to “第 14 章 性能优化与成本控制”">​</a></h2><ul><li>14.1 Token 经济学：降低 API 调用成本的策略</li><li>14.2 缓存机制：语义缓存与精确缓存的应用</li><li>14.3 响应速度优化：并发处理与流式架构</li><li>14.4 模型路由：根据任务难度动态选择模型</li><li>14.5 资源监控与告警：生产环境的稳定性保障</li></ul><h2 id="第-15-章-安全、伦理与合规" tabindex="-1">第 15 章 安全、伦理与合规 <a class="header-anchor" href="#第-15-章-安全、伦理与合规" aria-label="Permalink to “第 15 章 安全、伦理与合规”">​</a></h2><ul><li>15.1 提示词注入攻击与防御手段</li><li>15.2 数据隐私保护：PII 信息的识别与脱敏</li><li>15.3 内容安全：防止生成有害与偏见内容</li><li>15.4 合规性考量：版权、透明度与责任归属</li><li>15.5 安全审计与红队测试：主动发现系统漏洞</li></ul><h2 id="第-16-章-未来展望-通往-agi-之路" tabindex="-1">第 16 章 未来展望：通往 AGI 之路 <a class="header-anchor" href="#第-16-章-未来展望-通往-agi-之路" aria-label="Permalink to “第 16 章 未来展望：通往 AGI 之路”">​</a></h2><ul><li>16.1 具身智能：Agent 走进物理世界（机器人）</li><li>16.2 端侧模型：在手机与 PC 上运行本地 Agent</li><li>16.3 自进化 Agent：自我改进代码与目标的能力</li><li>16.4 结语：开发者在 AI 新时代的使命</li><li>16.5 附录：推荐学习资源与开源项目清单</li></ul>',34)])])}const u=i(t,[["render",r]]);export{c as __pageData,u as default};
